#!/bin/bash
# karabiner-win11-kr : install Karabiner-Elements + apply the Windows 11 Korean keyboard setup
# https://github.com/linchaindev/karabiner-win11-kr
set -e

echo "== 1/5 Checking Homebrew =="
if ! command -v brew >/dev/null 2>&1; then
  echo "Homebrew not found -> installing"
  /bin/bash -c "$(curl -fsSL https://raw.githubusercontent.com/Homebrew/install/HEAD/install.sh)"
  eval "$(/opt/homebrew/bin/brew shellenv)" 2>/dev/null || eval "$(/usr/local/bin/brew shellenv)"
fi

echo "== 2/5 Installing Karabiner-Elements =="
if ! brew list --cask karabiner-elements >/dev/null 2>&1 && [ ! -d "/Applications/Karabiner-Elements.app" ]; then
  brew install --cask karabiner-elements
else
  echo "Already installed -> skipping"
fi

echo "== 3/5 Deploying config =="
if [ -d ~/.config/karabiner ]; then
  BAK=~/.config/karabiner.bak-$(date +%Y%m%d-%H%M%S)
  mv ~/.config/karabiner "$BAK"
  echo "Backed up existing config: $BAK"
fi
TMPDIR_KWK=$(mktemp -d)
PAYLOAD_B64=""
echo "$PAYLOAD_B64" | base64 -d | tar xz -C "$TMPDIR_KWK"
mkdir -p ~/.config/karabiner/assets
cp "$TMPDIR_KWK/karabiner.json" ~/.config/karabiner/karabiner.json
cp -R "$TMPDIR_KWK/complex_modifications" ~/.config/karabiner/assets/
rm -rf "$TMPDIR_KWK"
echo "karabiner.json + rule files deployed"

echo "== 4/5 System settings =="
defaults write com.apple.HIToolbox AppleFnUsageType -int 1        # globe key = change input source
defaults write com.apple.HIToolbox TISRomanSwitchState -int 0     # disable Caps Lock ABC toggle
echo "Applied: globe key = change input source, Caps Lock Korean/English toggle off (a re-login makes it stick)"

echo "== 5/5 Launching Karabiner (triggers the permission prompt) =="
open -a "Karabiner-Elements"

cat <<'CHECKLIST'

---- Manual steps you still need to do ----
1. Approve the driver (system extension) popup in System Settings
2. Privacy & Security -> Input Monitoring -> allow karabiner_grabber
3. (Optional) System Settings -> Spotlight -> turn on Clipboard  <- for Cmd+Shift+V clipboard history
-------------------------------------------
CHECKLIST
